import { useState, useMemo, useRef, useEffect } from "react";
import { Moon, Sun, Trash2, X, Search, AlertTriangle, Check, Settings as SettingsIcon } from "lucide-react";
import { toast } from "sonner";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { usePreferences } from "@/lib/usePreferences";
import { Reveal } from "@/components/landing/motion";
import Breadcrumb from "@/components/ui/Breadcrumb";

const THEME_OPTIONS = [
  { value: "dark", label: "Dark", icon: Moon },
  { value: "light", label: "Light", icon: Sun },
];

const PRICE_FORMAT_OPTIONS = [
  { value: "compact", label: "Compact (1.2k)" },
  { value: "full", label: "Full (1,200.00)" },
];

function SettingSection({ title, children, id, hidden }) {
  if (hidden) return null;
  return (
    <div id={id} className="mb-10 scroll-mt-32">
      <h2 className="font-heading text-xl font-bold mb-4 text-white border-b border-white/10 pb-3">{title}</h2>
      <div className="space-y-3">{children}</div>
    </div>
  );
}

function SettingItem({ label, desc, children }) {
  return (
    <div className="flex items-center justify-between p-4 bg-white/[0.02] rounded-lg gap-4">
      <div className="min-w-0">
        <div className="font-mono text-sm text-zinc-300">{label}</div>
        {desc && <div className="text-[11px] text-zinc-500 mt-0.5">{desc}</div>}
      </div>
      <div className="shrink-0">{children}</div>
    </div>
  );
}

function ToggleSwitch({ checked, onChange }) {
  return (
    <label className="flex items-center gap-2 cursor-pointer">
      <input type="checkbox" checked={checked} onChange={(e) => onChange(e.target.checked)} className="sr-only" />
      <div className={`w-10 h-5 rounded-full flex items-center transition-colors ${checked ? "bg-emerald-500" : "bg-zinc-600"}`}>
        <div className={`w-4 h-4 rounded-full bg-white shadow transform transition-transform ${checked ? "translate-x-5" : "translate-x-0.5"}`} />
      </div>
    </label>
  );
}

function ThemeCard({ value, label, currentValue, onChange }) {
  const selected = value === currentValue;
  return (
    <button
      onClick={() => onChange(value)}
      className={`relative flex-1 rounded-xl border-2 p-4 transition-all cursor-pointer ${
        selected ? "border-emerald-500 bg-emerald-500/10" : "border-white/10 bg-white/[0.02] hover:border-white/30"
      }`}
    >
      {selected && (
        <div className="absolute top-2 right-2 w-5 h-5 rounded-full bg-emerald-500 flex items-center justify-center">
          <Check className="w-3 h-3 text-white" />
        </div>
      )}
      <div className={`h-16 rounded-lg mb-3 flex items-center justify-center ${value === "dark" ? "bg-zinc-900" : "bg-zinc-100"}`}>
        <div className={`w-12 h-6 rounded ${value === "dark" ? "bg-zinc-700" : "bg-zinc-300"}`} />
      </div>
      <div className="flex items-center gap-2 text-sm">
        {value === "dark" ? <Moon className="w-4 h-4 text-zinc-400" /> : <Sun className="w-4 h-4 text-amber-400" />}
        <span className="font-mono text-sm">{label}</span>
      </div>
    </button>
  );
}

function ConfirmModal({ open, title, message, confirmLabel, onConfirm, onCancel }) {
  const [typed, setTyped] = useState("");
  const inputRef = useRef(null);

  useEffect(() => {
    if (open) {
      setTyped("");
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [open]);

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm" onClick={onCancel}>
      <div className="bg-bg-base border border-red-500/20 rounded-2xl max-w-md w-full p-6 shadow-2xl" onClick={(e) => e.stopPropagation()}>
        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-red-500/10 border border-red-500/30 mb-4">
          <AlertTriangle className="w-6 h-6 text-red-400" />
        </div>
        <h3 className="font-heading text-xl font-bold mb-2">{title}</h3>
        <p className="text-zinc-400 text-sm leading-relaxed mb-4">{message}</p>
        <p className="text-[11px] text-zinc-500 mb-3 font-mono">Type <strong className="text-red-400">DELETE</strong> to confirm:</p>
        <input
          ref={inputRef}
          type="text"
          value={typed}
          onChange={(e) => setTyped(e.target.value)}
          placeholder="DELETE"
          className="w-full bg-white/[0.04] border border-white/10 rounded-lg px-4 py-2.5 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-red-500/50 mb-4 font-mono"
        />
        <div className="flex gap-3">
          <button onClick={onCancel} className="flex-1 border border-white/10 hover:border-white/30 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2.5 rounded-sm transition-colors">
            Cancel
          </button>
          <button
            onClick={onConfirm}
            disabled={typed !== "DELETE"}
            className="flex-1 bg-red-500 hover:bg-red-400 disabled:bg-red-500/30 disabled:pointer-events-none text-black font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2.5 rounded-sm transition-colors"
          >
            {confirmLabel || "Delete"}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function SettingsPage() {
  const { preferences, updatePreferences } = usePreferences();
  const [searchQ, setSearchQ] = useState("");
  const [showClearModal, setShowClearModal] = useState(false);
  const searchRef = useRef(null);

  const sections = useMemo(() => [
    {
      id: "appearance",
      title: "Appearance",
      keywords: ["theme", "dark", "light", "appearance", "look"],
      content: (
        <>
          <SettingItem label="Theme" desc="Choose your preferred appearance">
            <div className="flex gap-3 min-w-[240px]">
              {THEME_OPTIONS.map((opt) => (
                <ThemeCard
                  key={opt.value}
                  value={opt.value}
                  label={opt.label}
                  currentValue={preferences.theme}
                  onChange={(theme) => {
                    updatePreferences({ theme });
                    document.documentElement.classList.toggle("dark", theme === "dark");
                    toast("Theme changed to " + theme);
                  }}
                />
              ))}
            </div>
          </SettingItem>
          <SettingItem label="Price Format" desc="How coin values are displayed">
            <div className="flex gap-1 bg-white/[0.04] p-1 rounded">
              {PRICE_FORMAT_OPTIONS.map((opt) => (
                <label key={opt.value} className="flex items-center gap-2 p-2 rounded cursor-pointer hover:bg-white/[0.04] transition-colors">
                  <input type="radio" value={opt.value} checked={opt.value === preferences.priceFormat}
                    onChange={() => { updatePreferences({ priceFormat: opt.value }); toast("Price format updated"); }}
                    className="sr-only"
                  />
                  <div className={`w-4 h-4 rounded-full border-2 ${opt.value === preferences.priceFormat ? "border-emerald-400 bg-emerald-400" : "border-zinc-500"}`}>
                    {opt.value === preferences.priceFormat && <div className="w-1.5 h-1.5 rounded-full bg-white ml-[3px] mt-[3px]" />}
                  </div>
                  <span className="text-sm font-mono">{opt.label}</span>
                </label>
              ))}
            </div>
          </SettingItem>
        </>
      ),
    },
    {
      id: "notifications",
      title: "Notifications",
      keywords: ["notifications", "alerts", "price", "browser", "sound", "bell"],
      content: (
        <>
          <SettingItem label="Price Alerts" desc="Receive toast notifications when prices change">
            <ToggleSwitch
              checked={preferences.notifications?.priceAlerts ?? true}
              onChange={(enabled) => {
                updatePreferences({ notifications: { ...preferences.notifications, priceAlerts: enabled } });
                toast(enabled ? "Price alerts enabled" : "Price alerts disabled");
              }}
            />
          </SettingItem>
          <SettingItem label="Browser Notifications" desc="System notification popups (requires permission)">
            <ToggleSwitch
              checked={preferences.notifications?.browser ?? false}
              onChange={(enabled) => {
                if (!enabled) {
                  updatePreferences({ notifications: { ...preferences.notifications, browser: false } });
                  toast("Browser notifications disabled");
                  return;
                }

                if (Notification.permission === "denied") {
                  toast.error("Notifications are blocked", {
                    description: "Please enable them in your browser settings for this site.",
                  });
                  return;
                }

                if (Notification.permission === "default") {
                  Notification.requestPermission().then((perm) => {
                    const granted = perm === "granted";
                    updatePreferences({ notifications: { ...preferences.notifications, browser: granted } });
                    if (granted) toast.success("Browser notifications enabled");
                    else toast.error("Permission denied");
                  });
                } else {
                  updatePreferences({ notifications: { ...preferences.notifications, browser: true } });
                  toast.success("Browser notifications enabled");
                }
              }}
            />
          </SettingItem>
          <SettingItem label="Sound Alerts" desc="Play a sound on new price alerts (coming soon)">
            <ToggleSwitch
              checked={preferences.notifications?.sound ?? false}
              onChange={(enabled) => {
                updatePreferences({ notifications: { ...preferences.notifications, sound: enabled } });
              }}
            />
          </SettingItem>
        </>
      ),
    },
    {
      id: "data",
      title: "Data & Privacy",
      keywords: ["data", "privacy", "clear", "delete"],
      content: (
        <>
          <SettingItem label="Clear All Data" desc="Permanently delete all local preferences and favorites">
            <button
              onClick={() => setShowClearModal(true)}
              className="inline-flex items-center gap-2 border border-red-500/30 hover:border-red-500 text-red-400 hover:text-red-300 font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2 rounded-sm transition-colors"
            >
              <Trash2 className="w-3.5 h-3.5" /> Clear
            </button>
          </SettingItem>
        </>
      ),
    },
  ], [preferences, updatePreferences]);

  const query = searchQ.toLowerCase().trim();
  const hasSearch = query.length > 0;

  const sectionVisibility = useMemo(() => {
    if (!hasSearch) return sections.map(() => true);
    return sections.map((s) =>
      s.keywords.some((kw) => kw.includes(query)) || s.title.toLowerCase().includes(query)
    );
  }, [sections, hasSearch, query]);

  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape" && searchQ) { setSearchQ(""); searchRef.current?.blur(); }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [searchQ]);

  const handleClearData = () => {
    try {
      const keys = Object.keys(localStorage).filter((k) => k.startsWith("castia."));
      keys.forEach((k) => localStorage.removeItem(k));
      toast("All local data cleared");
      setTimeout(() => window.location.reload(), 800);
    } catch { toast("Failed to clear data"); }
    setShowClearModal(false);
  };

  return (
    <div className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-4xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <Breadcrumb
              items={[
                { label: "Home", href: "/" },
                { label: "Settings" },
              ]}
              icon={SettingsIcon}
              color="text-emerald-400"
            />
            <h1 className="font-heading text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95] mb-8">
              Your <span className="text-emerald-400">Settings</span>
            </h1>
            <p className="text-zinc-400 max-w-2xl text-lg mb-8">
              Customize your Castia Market Insight experience.
            </p>
          </Reveal>

          {/* Settings search */}
          <Reveal delay={0.05}>
            <div className="relative mb-10 max-w-md">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500 pointer-events-none" />
              <input
                ref={searchRef}
                type="text"
                value={searchQ}
                onChange={(e) => setSearchQ(e.target.value)}
                placeholder="Search settings…"
                className="w-full bg-white/[0.04] border border-white/10 rounded-lg pl-10 pr-4 py-2.5 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-emerald-500/50 transition-colors"
              />
              {searchQ && (
                <button onClick={() => setSearchQ("")} className="absolute right-3 top-1/2 -translate-y-1/2 text-zinc-500 hover:text-white">
                  <X className="w-3.5 h-3.5" />
                </button>
              )}
            </div>
          </Reveal>

          {/* Sidebar nav (desktop) */}
          <div className="flex gap-10">
            <div className="hidden lg:block w-48 shrink-0">
              <div className="sticky top-32 space-y-1">
                {sections.map((s, i) => (
                  <a
                    key={s.id}
                    href={`#${s.id}`}
                    className={`block text-xs font-mono uppercase tracking-wider py-1.5 px-3 rounded-sm transition-colors ${
                      sectionVisibility[i] ? "text-zinc-400 hover:text-white" : "text-zinc-700 pointer-events-none"
                    }`}
                  >
                    {s.title}
                  </a>
                ))}
              </div>
            </div>

            <div className="flex-1 min-w-0">
              {hasSearch && !sectionVisibility.some(Boolean) && (
                <div className="text-center py-12">
                  <p className="text-zinc-500 text-sm">No settings match <strong className="text-zinc-300">{searchQ}</strong></p>
                </div>
              )}

              {sections.map((s, i) => (
                <SettingSection key={s.id} id={s.id} title={s.title} hidden={!sectionVisibility[i]}>
                  {s.content}
                </SettingSection>
              ))}
            </div>
          </div>
        </div>
      </main>
      <Footer />

      <ConfirmModal
        open={showClearModal}
        title="Clear all data"
        message="This will permanently delete all your preferences, favorites, compare list, and local data. This action cannot be undone."
        confirmLabel="DELETE"
        onConfirm={handleClearData}
        onCancel={() => setShowClearModal(false)}
      />
    </div>
  );
}
